const n3SelectionRecord = (id, correct, values, hint, explanation) => Object.freeze({
  id,
  type: id.includes("passage") ? "passage-blank" : "selection",
  correct,
  hint,
  rationales: Object.freeze(Object.fromEntries(values.map(value => [
    value,
    value === correct
      ? `Correct. ${explanation}`
      : `This choice does not create the source, certainty, negation, or concession relationship required by the complete sentence.`,
  ]))),
});
const n3OrderRecord = (id, correct, hint, explanation) => Object.freeze({
  id,
  type: "ordering",
  correct: Object.freeze(correct),
  hint,
  rationales: Object.freeze({ order: `Correct. ${explanation}` }),
});
const n3DetailedSelectionRecord = (id, correct, hint, rationales) => Object.freeze({
  id,
  type: id.includes("passage") ? "passage-blank" : "selection",
  correct,
  hint,
  rationales: Object.freeze(rationales),
});

